import{_ as a,o,c as n,j as e,a as r}from"./chunks/framework.DH-ORP1j.js";const _=JSON.parse('{"title":"中共一大：1921年，上海-嘉兴。中共成","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-23.md","filePath":"notes/note-23.md"}'),s={name:"notes/note-23.md"};function c(d,t,l,i,p,m){return o(),n("div",null,[...t[0]||(t[0]=[e("h1",{id:"中共一大-1921年-上海-嘉兴。中共成",tabindex:"-1"},[r("中共一大：1921年，上海-嘉兴。中共成 "),e("a",{class:"header-anchor",href:"#中共一大-1921年-上海-嘉兴。中共成","aria-label":'Permalink to "中共一大：1921年，上海-嘉兴。中共成"'},"​")],-1),e("p",null,"1、中共一大：1921年，上海-嘉兴。中共成立是开天辟地的大事变，自从有了中共，中国革命面貌就焕然一新。 2、中共二大：1922年。任务：打倒军阀、推翻帝国主义，将中国统一为真正的民主共和国。第一次提出明确反帝反封建革命纲领。 3、中共三大：1923年，广州。与国民党合作，建立革命统一战线。 4、八七会议：1927年，汉口。确定实行土地革命和武装反抗国民党反动派的方针，发动秋收起义，“政权是由枪杆子中取得的”。 5、遵义会议：1935年，遵义。纠正了“左”的错误，确立了以毛泽东为主要代表马克思主义正确路线在党中央的领导地位。生死攸关转折点。 6、中共七大：1945年，延安。毛泽东思想成为党的指导思想和入党章。 7、中共七届二中全会：1949年，西柏坡，党的工作重心从乡村转向城市；我国从落后农业国变先进工业国。 8、中共八大：1956年，北京。分析主要矛盾，任务是把我国从落后农业国变先进工业国。探索建设社会主义道路的良好开端。 9、中共八大二次会议：1958年，“鼓足干劲，力争上游，多快好省地建设社会主义”的总路线。（错误） 10、中共十一届三中全：1978年。以经济建设为中心，改革开放，深远意义的伟大转折。 11、中共十二大：1982年，提出“建设有中国特色的社会主义”。 12、中共十三大：一个中心，两个基本点。 13、中共十四大：1992年，提出建立社会主义市场经济体制。邓论武装全党。 14、中共十五大：1997年，邓论成为党的指导思想和入党章。 15、中共十六大：“三个代表”成为党的指导思想。 16、中共十八大：科学发展观成为党的指导思想。 17、中共十九大：习近平新时代中国特色社会主义思想成为党的指导思想。 社会主义建设成就的影响：1956-1976年，初步形成了独立的、比较完整的工业体系和国民经济体系，为现代化建设打下了坚实的物质基础。",-1)])])}const h=a(s,[["render",c]]);export{_ as __pageData,h as default};
